<?php require 'config/db.php'; require 'includes/auth.php'; require_admin();
if(isset($_GET['delete'])){$pdo->prepare('DELETE FROM service_applications WHERE id=?')->execute([$_GET['delete']]); header('Location: applications.php'); exit;}
if($_SERVER['REQUEST_METHOD']==='POST' && isset($_POST['status'],$_POST['id'])){$pdo->prepare('UPDATE service_applications SET status=? WHERE id=?')->execute([$_POST['status'],$_POST['id']]); $message='Статус заявки обновлен';}
$apps=$pdo->query('SELECT a.*, s.name service_name, s.price FROM service_applications a JOIN services s ON s.id=a.service_id ORDER BY a.id DESC')->fetchAll(); include 'includes/header.php'; ?>
<section class="page-hero container"><div class="page-title"><h1>Заявки с сайта</h1><p>Клиенты выбирают услуги ДМС, а администрация обрабатывает обращения.</p></div></section><section class="container"><?php if(!empty($message)): ?><div class="alert"><?= e($message) ?></div><?php endif; ?><div class="table-wrap"><table class="table"><tr><th>ID</th><th>Клиент</th><th>Контакты</th><th>Услуга</th><th>Комментарий</th><th>Статус</th><th>Действие</th></tr><?php foreach($apps as $a): ?><tr><td><?= $a['id'] ?></td><td><?= e($a['full_name']) ?><br><small><?= e($a['birth_date']) ?></small></td><td><?= e($a['phone']) ?><br><?= e($a['email']) ?></td><td><?= e($a['service_name']) ?><br><small><?= number_format($a['price'],0,',',' ') ?> ₽</small></td><td><?= e($a['comment']) ?></td><td><form method="post" class="inline-form"><input type="hidden" name="id" value="<?= $a['id'] ?>"><select name="status"><option value="new" <?= $a['status']=='new'?'selected':'' ?>>Новая</option><option value="processing" <?= $a['status']=='processing'?'selected':'' ?>>В обработке</option><option value="approved" <?= $a['status']=='approved'?'selected':'' ?>>Одобрена</option><option value="rejected" <?= $a['status']=='rejected'?'selected':'' ?>>Отклонена</option></select><button class="btn mini" type="submit">OK</button></form></td><td><a class="btn danger" onclick="return confirm('Удалить заявку?')" href="?delete=<?= $a['id'] ?>">Удалить</a></td></tr><?php endforeach; ?><?php if(!$apps): ?><tr><td colspan="7" class="empty">Заявок пока нет</td></tr><?php endif; ?></table></div></section><?php include 'includes/footer.php'; ?>
